import{_ as d,o as r,c as a,ag as o}from"./chunks/framework.CNG7EpJN.js";const g=JSON.parse('{"title":"KDS","description":"","frontmatter":{"title":"KDS"},"headers":[],"relativePath":"tenant/07-kds.md","filePath":"tenant/07-kds.md"}'),e={name:"tenant/07-kds.md"};function i(l,t,n,s,h,c){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="_7-kds-キッチンディスプレイ" tabindex="-1">7. KDS（キッチンディスプレイ） <a class="header-anchor" href="#_7-kds-キッチンディスプレイ" aria-label="Permalink to &quot;7. KDS（キッチンディスプレイ）&quot;">​</a></h1><p>KDSは、注文を厨房に表示する画面です。紙伝票の代わりに、調理状況、提供状況、注文の優先度を確認できます。</p><h2 id="開店時に確認すること" tabindex="-1">開店時に確認すること <a class="header-anchor" href="#開店時に確認すること" aria-label="Permalink to &quot;開店時に確認すること&quot;">​</a></h2><ol><li>KDS用端末でKDS画面を開きます。</li><li>店舗、表示するステーション、音量、画面維持の状態を確認します。</li><li>黒い起動画面が表示されたら <strong>KDSを開始</strong> をタップします。通知音、音声コマンド、画面維持の準備が始まります。</li><li>ヘッダーの <strong>開店前チェック</strong> を押し、KDS通信、自動更新、通知音、マイク入力、画面維持、ステーションを確認します。</li><li>必要に応じて <strong>着手時間</strong> を確認します。テイクアウト受取時刻や予約時刻の何分前から厨房に出すかを、テイクアウト・予約・カテゴリ別に設定できます。</li></ol><div class="tip custom-block"><p class="custom-block-title">着手時間の例</p><ul><li>寿司・コース料理など準備に時間がかかるカテゴリ: 30分前</li><li>通常料理: 20分前</li><li>ドリンク・簡単なデザート: 5分前</li></ul><p>設定はKDS端末ごとに保存されます。厨房端末を複数台使う場合は、各端末で同じ設定になっているか開店前に確認してください。</p></div><h2 id="kdsの基本操作" tabindex="-1">KDSの基本操作 <a class="header-anchor" href="#kdsの基本操作" aria-label="Permalink to &quot;KDSの基本操作&quot;">​</a></h2><ol><li>注文が入るとカードとして表示されます。</li><li>調理を始めたらステータスを更新します。</li><li>料理が完成したら「完成」にします。ホールのハンディへ料理完成通知が出ます。</li><li>提供が完了したら「提供済み」にし、画面から消します。</li><li>間違って押した場合は10秒取り消しまたは配膳取消で戻します。</li></ol><h2 id="ステータスの意味と連動" tabindex="-1">ステータスの意味と連動 <a class="header-anchor" href="#ステータスの意味と連動" aria-label="Permalink to &quot;ステータスの意味と連動&quot;">​</a></h2><p>KDSのステータスは、注文全体と品目単位の両方で管理されます。</p><table tabindex="0"><thead><tr><th>ステータス</th><th>厨房での意味</th><th>連動</th></tr></thead><tbody><tr><td>受付</td><td>注文直後。まだ調理に入っていない</td><td>KDSに新着カードとして表示</td></tr><tr><td>調理中</td><td>厨房が着手した</td><td>調理開始時刻が残る</td></tr><tr><td>提供待ち</td><td>料理が完成し、ホール配膳待ち</td><td>ハンディの運用タブに料理完成通知を作成</td></tr><tr><td>提供済み</td><td>お客様へ提供済み</td><td>品目が完了扱いになり、全品提供済みなら注文も提供済みへ進む</td></tr><tr><td>キャンセル</td><td>作らない、または取り消した品目</td><td>完了判定から除外</td></tr></tbody></table><p>品目を <strong>完成</strong> にすると、ハンディ側に <code>product_ready</code> の呼び出しが出ます。ホールが配膳対応済みにすると、該当品目は提供済みへ連動します。厨房側で全品をまとめて提供済みにした場合も、注文全体が完了方向へ進みます。</p><p>混在状態の注文では、誤って全品を戻さないよう、一括操作が抑制される場面があります。品目単位で状態が違う場合は、対象の品目を個別に操作してください。</p><h3 id="expeditor-まとめ表示-モード" tabindex="-1">Expeditor（まとめ表示）モード <a class="header-anchor" href="#expeditor-まとめ表示-モード" aria-label="Permalink to &quot;Expeditor（まとめ表示）モード&quot;">​</a></h3><p>Expeditorモードは、提供順に特化した単一カラムのリスト表示です。</p><ul><li><strong>メリット</strong>: 調理の優先順位が明確になり、提供ミスを防げます。</li><li><strong>活用シーン</strong>: 注文数が多いピーク時や、デリバリー・テイクアウトのパッキング作業に最適です。</li></ul><p>まとめ表示では、提供待ち、遅れ、テイクアウト受取時刻、予約時刻などを見ながら、厨房とホールが同じ優先順位で動けます。通常の3列表示に戻したい場合は、画面ボタンまたは音声コマンドの <strong>通常表示</strong> を使います。</p><h2 id="画面の見方" tabindex="-1">画面の見方 <a class="header-anchor" href="#画面の見方" aria-label="Permalink to &quot;画面の見方&quot;">​</a></h2><ul><li><strong>受付</strong>: 注文直後で、まだ調理を始めていない品目です。</li><li><strong>調理中</strong>: 調理開始済みの品目です。</li><li><strong>提供待ち</strong>: 料理完成済みで、ホールの配膳待ちです。</li><li><strong>ステーション状況帯</strong>: ステーション別の注文数、未完了品目数、受付、調理中、提供待ち、最上位の注意理由を表示します。</li><li><strong>端末状態帯</strong>: 最終更新、通信遅延、stale/live、音声成功時刻、通信異常を常時表示します。</li></ul><p>ステーション状況帯は、担当場所ごとの負荷を見るための帯です。未完了数が多い、提供待ちが溜まっている、遅れが出ているステーションは強調されます。ピーク中は、まず状況帯を見て「どこが詰まっているか」を確認してください。</p><p>予約から着席した卓の注文カードには、予約者名、人数、予約時刻、コース、予約メモ、好み、注意点、来店回数などの予約文脈が表示されます。予約顧客にアレルギー情報がある場合は、通常の注文メモとは別に「予約アレルギー」として強調されます。</p><p>端末状態帯が赤の場合は、KDS端末が止まっている、通信が不安定、または古いデータを表示している可能性があります。厨房作業を進める前に、Wi-Fi、端末のスリープ、ブラウザの再読み込みを確認してください。</p><h2 id="ステーション" tabindex="-1">ステーション <a class="header-anchor" href="#ステーション" aria-label="Permalink to &quot;ステーション&quot;">​</a></h2><p>ステーションは「厨房」「ドリンク」「デザート」など、担当場所ごとの表示分けです。商品ごとに適切なステーションを設定すると、担当者が必要な注文だけを確認できます。</p><p>ステーションを選ぶと、そのステーションで必要な品目だけが表示されます。注文が見当たらない場合は、まず <strong>全品目</strong> に戻して確認してください。</p><p>ステーション設定は、管理画面の <strong>店舗設定 → KDSステーション</strong> で行います。カテゴリやメニュー品目とステーションの紐づけがずれていると、注文が想定のKDSに表示されません。</p><h2 id="テイクアウト・予約の表示" tabindex="-1">テイクアウト・予約の表示 <a class="header-anchor" href="#テイクアウト・予約の表示" aria-label="Permalink to &quot;テイクアウト・予約の表示&quot;">​</a></h2><p>テイクアウト注文は、受取時刻とお客様名を見ながら準備します。着手時間設定により、受取時刻の何分前からKDSに出すかを調整できます。</p><p>予約から着席した注文では、予約者名、予約時刻、人数、コース、メモ、好み、注意点、アレルギーが表示されます。アレルギーは通常メモよりも見落としやすいため、カード内の予約アレルギー表示を必ず確認してください。</p><h2 id="取り消し・戻し操作" tabindex="-1">取り消し・戻し操作 <a class="header-anchor" href="#取り消し・戻し操作" aria-label="Permalink to &quot;取り消し・戻し操作&quot;">​</a></h2><p>誤って状態を進めた場合は、直後であれば画面上の取り消し操作、または音声の <strong>戻して</strong> を使います。すでにホール側で配膳対応済みになっている場合は、ハンディ側の通知や注文状態も確認してください。</p><p>調理済み・提供済みを戻す操作は、現場混乱につながりやすいため、対象の卓・品目・数量を確認してから行ってください。会計済みの商品を厨房側だけで戻しても、会計は自動で取り消されません。</p><h2 id="推奨端末" tabindex="-1">推奨端末 <a class="header-anchor" href="#推奨端末" aria-label="Permalink to &quot;推奨端末&quot;">​</a></h2><p>KDSはAndroidタブレット（10インチ以上）+ Google Chrome最新版を <strong>標準環境</strong> としています。iPad/Safariでも画面は表示できますが、音声コマンドや通知音が安定しないためサポート対象外です。詳細は「KDSデバイス端末ガイド」をご覧ください。</p><h2 id="音声コマンド" tabindex="-1">音声コマンド <a class="header-anchor" href="#音声コマンド" aria-label="Permalink to &quot;音声コマンド&quot;">​</a></h2><p>音声コマンドは Android の Google Chrome 最新版での利用を標準としています。Safari / iPad では認識が安定しにくいため、音声操作を使う場合は Android 端末をご利用ください。</p><p>周囲の騒音が大きい場合は認識しにくくなるため、必要に応じて手操作で対応してください。騒がしい厨房や広い店内では、<strong>マイク付き片耳Bluetoothヘッドセット</strong>（任意の推奨備品）の併用もご検討ください。詳しくは「23. KDSデバイス端末ガイド」をご覧ください。</p><p>主な音声操作:</p><table tabindex="0"><thead><tr><th>言葉</th><th>動作</th></tr></thead><tbody><tr><td><code>T01 調理開始</code></td><td>T01の注文を調理中へ進める</td></tr><tr><td><code>T01 完成</code></td><td>T01の注文を提供待ちへ進める</td></tr><tr><td><code>T01 提供済み</code></td><td>T01の注文を提供済みにする</td></tr><tr><td><code>T01 残り</code></td><td>その卓の未完成品を確認する</td></tr><tr><td><code>まとめ表示</code> / <code>通常表示</code></td><td>Expeditor表示と通常3列表示を切り替える</td></tr><tr><td><code>品切れ一覧</code> / <code>品切れ管理</code></td><td>品切れ確認または品切れ管理画面へ移動する</td></tr><tr><td><code>音声再起動</code></td><td>音声認識だけを再起動する</td></tr><tr><td><code>音声診断</code></td><td>端末の音声認識状態を確認する</td></tr></tbody></table><p>厨房でよく使う操作はAIを使わないファストパスで処理します。ヘッダーの <strong>AIシェフON/OFF</strong> は、AIシェフパネルと、ファストパスで処理できない曖昧な言い回しの補助解析をまとめて切り替える設定です。通常運用ではOFF推奨です。</p><h2 id="営業中の確認ポイント" tabindex="-1">営業中の確認ポイント <a class="header-anchor" href="#営業中の確認ポイント" aria-label="Permalink to &quot;営業中の確認ポイント&quot;">​</a></h2><ul><li>KDS端末が常に充電または給電されていること</li><li>Wi-Fiが安定していること</li><li>画面がスリープしない設定になっていること</li><li>端末状態帯の「最終更新」「遅延」「stale/live」を見ること</li><li>注文カードの更新が止まっていないこと</li><li>音声操作を使う場合は、端末状態帯の「音声成功」とヘッダーの「音声診断」を確認すること</li></ul><h2 id="困ったとき" tabindex="-1">困ったとき <a class="header-anchor" href="#困ったとき" aria-label="Permalink to &quot;困ったとき&quot;">​</a></h2><table tabindex="0"><thead><tr><th>症状</th><th>対処</th></tr></thead><tbody><tr><td>注文が表示されない</td><td>店舗、ステーション、ネットワークを確認してください。ステーションを <strong>全品目</strong> に戻すと切り分けしやすくなります。</td></tr><tr><td>端末状態帯が赤い</td><td>通信停止、stale、または最終更新20秒超の可能性があります。Wi-Fi確認、画面スリープ解除、ブラウザ再読み込みを行ってください。</td></tr><tr><td>音が鳴らない</td><td>端末音量、ブラウザの音声許可、ミュート設定、起動時の <strong>KDSを開始</strong> タップを確認してください。Safariでは通知音が安定しないため、Android Chromeをお試しください。</td></tr><tr><td>音声操作が反応しない</td><td>AndroidのGoogle Chrome最新版を利用し、マイク許可、音声ON、音声診断を確認してください。Safari/iPadは音声コマンド非対応です。</td></tr><tr><td>画面更新が遅い</td><td>端末状態帯の遅延秒数とWi-Fi環境を確認し、必要に応じて再読み込みしてください。</td></tr><tr><td>テイクアウトや予約が早く/遅く表示される</td><td>ヘッダーの <strong>着手時間</strong> を確認してください。カテゴリ別設定が優先されます。</td></tr></tbody></table>',43)])])}const b=d(e,[["render",i]]);export{g as __pageData,b as default};
